import express from 'express';
import 'dotenv/config';
import dns from 'dns';
import cors from 'cors';
import compression from 'compression';
import helmet from 'helmet';
import rateLimit from 'express-rate-limit';
import chalk from 'chalk';

// Import database
import { connectDatabase, disconnectDatabase, isDatabaseConnected } from './config/database.js';

// Import middleware
import requestLogger from './middleware/requestLogger.js';
import errorHandler from './middleware/errorHandler.js';
import { securityHeaders, sanitizeData } from './middleware/security.js';
import { globalLimiter, authLimiter } from './middleware/rateLimiter.js';
import { cacheMiddleware } from './middleware/cache.js';

// Import utilities
import { ResponseHelper, Logger } from './utils/helper.js';


const app = express();
const PORT = process.env.PORT || 5000;
const NODE_ENV = process.env.NODE_ENV || 'development';
const API_VERSION = 'v1';

// ============================================
// MIDDLEWARE SETUP
// ============================================

// Security Headers
app.use(securityHeaders);

// Body Parsing
app.use(express.json({ limit: '50mb' }));
app.use(express.urlencoded({ limit: '50mb', extended: true }));

// Compression
app.use(compression({
  level: NODE_ENV === 'production' ? 6 : 3,
  threshold: 1024
}));

// CORS Configuration
app.use(cors({
  origin: process.env.CORS_ORIGIN?.split(',') || '*',
  credentials: true,
  methods: ['GET', 'POST', 'PUT', 'PATCH', 'DELETE', 'OPTIONS'],
  allowedHeaders: ['Content-Type', 'Authorization'],
  maxAge: 86400 // 24 hours
}));

// Rate Limiting
app.use(`/api/auth`, authLimiter);
app.use(`/api`, globalLimiter);

// Data Sanitization
app.use(sanitizeData);

// Request Logging
app.use(requestLogger);

// Cache Middleware (for GET requests)
app.use(cacheMiddleware(300)); // 5 minutes cache

// ============================================
// ROUTES SETUP
// ============================================

// Health Check & API Info
app.get('/health', (req, res) => {
  res.status(200).json({
    status: 'OK',
    uptime: process.uptime(),
    timestamp: new Date().toISOString(),
    environment: NODE_ENV,
    database: isDatabaseConnected() ? 'Connected' : 'Disconnected',
    version: API_VERSION
  });
});

app.get(`/api/health`, (req, res) => {
  res.status(200).json({
    status: 'OK',
    uptime: process.uptime(),
    timestamp: new Date().toISOString(),
    environment: NODE_ENV,
    database: isDatabaseConnected() ? 'Connected' : 'Disconnected',
    version: API_VERSION
  });
});

app.get(`/api`, (req, res) => {
  res.status(200).json({
    success: true,
    message: 'Backend API Server',
    version: API_VERSION,
    environment: NODE_ENV,
    endpoints: {
      health: '/health',
      documentation: `/api/docs`,
      status: `/api/status`
    }
  });
});

app.get(`/api/status`, (req, res) => {
  res.status(200).json({
    success: true,
    status: 'running',
    database: isDatabaseConnected() ? 'connected' : 'disconnected',
    memory: process.memoryUsage(),
    uptime: process.uptime()
  });
});

// Import all routes
// Routes will be auto-registered here
// __ROUTES__

// ============================================
// IMPORTANT: API URL Configuration
// ============================================
// Routes are registered with /api prefix (e.g., app.use(`/api/users`, usersRoutes))
// Frontend VITE_API_URL should be: http://localhost:5000 (WITHOUT /api)
// Frontend will then call: http://localhost:5000/api/users
// 
// âŒ WRONG: VITE_API_URL = http://localhost:5000/api
// This would result in: http://localhost:5000/api/api/users (404!)
// 
// âœ… CORRECT: VITE_API_URL = http://localhost:5000
// This results in: http://localhost:5000/api/users (âœ“ works!)
// ============================================

// ============================================
// 404 ERROR HANDLER
// ============================================
app.use((req, res) => {
  res.status(404).json({
    success: false,
    message: 'Endpoint not found',
    path: req.path,
    method: req.method,
    status: 404
  });
});

// ============================================
// GLOBAL ERROR HANDLER
// ============================================
app.use(errorHandler);

// ============================================
// SERVER STARTUP
// ============================================

async function startServer() {
  try {
    // Connect to database
    await connectDatabase();

    // Start server
    const server = app.listen(PORT, () => {
      Logger.info('Server started successfully', {
        port: PORT,
        environment: NODE_ENV,
        pid: process.pid
      });

      console.log(chalk.cyan('\nðŸš€ Backend Server Running\n'));
      console.log(chalk.white('   URL:       '), chalk.bold(`http://localhost:${PORT}`));
      console.log(chalk.white('   API:       '), chalk.bold(`http://localhost:${PORT}/api`));
      console.log(chalk.white('   Health:    '), chalk.bold(`http://localhost:${PORT}/health`));
      console.log(chalk.white('   Status:    '), chalk.bold(`http://localhost:${PORT}/api/status`));
      console.log(chalk.white('   Env:       '), chalk.bold(NODE_ENV));
      console.log(chalk.gray('\nâ”â”â”â”â”â”â”â”â”â”â”â”â”â”â”â”â”â”â”â”â”â”â”â”â”â”â”â”â”â”â”â”â”â”â”â”\n'));
    });

    // Graceful shutdown
    process.on('SIGINT', async () => {
      console.log(chalk.yellow('\nâ›” Shutting down gracefully...\n'));
      
      server.close(async () => {
        await disconnectDatabase();
        Logger.info('Server shut down successfully');
        process.exit(0);
      });

      // Force shutdown after 10 seconds
      setTimeout(() => {
        console.error(chalk.red('Force shutting down...'));
        process.exit(1);
      }, 10000);
    });

    // Handle uncaught exceptions
    process.on('uncaughtException', (error) => {
      Logger.error('Uncaught Exception', error);
      console.error(chalk.red('âŒ Uncaught Exception:'), error.message);
      process.exit(1);
    });

    // Handle unhandled promise rejections
    process.on('unhandledRejection', (reason, promise) => {
      Logger.error('Unhandled Rejection', reason);
      console.error(chalk.red('âŒ Unhandled Rejection:'), reason);
    });

  } catch (error) {
    Logger.error('Server startup failed', error);
    console.error(chalk.red('âŒ Server startup failed:'), error.message);
    process.exit(1);
  }
}

// ============================================
// START APPLICATION
// ============================================

if (process.env.NODE_ENV !== 'test') {
  startServer();
}

export default app;

